$_MODULE['<{retractationcommande}prestashop>modal_c41af0bc59217001d2912ae37146555b'] = 'Potwierdź odstąpienie';
$_MODULE['<{retractationcommande}prestashop>modal_f64e4c1e50abe85bbda9fd9abadcaa91'] = 'Po potwierdzeniu Twój wniosek o odstąpienie zostanie przekazany do naszego działu obsługi klienta, a na Twój adres e-mail zostanie wysłane potwierdzenie odbioru wraz z egzemplarzem PDF (art. L221-21 francuskiego Kodeksu konsumenckiego). Po weryfikacji warunków (termin ustawowy, wyłączenia z art. L221-28) zostanie Ci przekazana procedura zwrotu — prosimy nie odsyłać produktów przed jej otrzymaniem. Zwrot następuje najpóźniej w ciągu 14 dni od odzyskania towaru lub otrzymania dowodu wysyłki (koszty dostawy wliczone w przypadku całkowitego odstąpienia, proporcjonalnie w pozostałych przypadkach). Koszty odesłania ponosi konsument.';
$_MODULE['<{retractationcommande}prestashop>modal_a50e61a0c90d69685028d751c58e4b92'] = 'Po potwierdzeniu Twój wniosek o odstąpienie zostanie przekazany do naszego działu obsługi klienta, a na Twój adres e-mail zostanie wysłane potwierdzenie odbioru wraz z egzemplarzem PDF (art. L221-21 francuskiego Kodeksu konsumenckiego). Ponieważ Twoje zamówienie nie zostało jeszcze wysłane, zwrot produktu nie będzie konieczny: po weryfikacji (wyłączenia z art. L221-28) wysyłka zostanie anulowana, a całość wpłaconych kwot zostanie zwrócona najpóźniej w ciągu 14 dni od Twojego wniosku tym samym sposobem płatności.';
$_MODULE['<{retractationcommande}prestashop>formulaire_c690c88abeab5fe0fa53c961a8c22564'] = 'Skorzystać z prawa do odstąpienia';
$_MODULE['<{retractationcommande}prestashop>formulaire_d80f966c0798503a14b4ca0d0cc6f7fa'] = 'Zgodnie z artykułami L221-18 i następnymi francuskiego Kodeksu konsumenckiego przysługuje Ci termin';
$_MODULE['<{retractationcommande}prestashop>formulaire_5f1fe455db6e9cab75f31be47d4a301f'] = 'dni';
