$_MODULE['<{retractationcommande}prestashop>formulaire_1e8ba54ca05a4d16b3314cd53c6d7847'] = 'Prawo do odstąpienia możliwe do wykonania';
$_MODULE['<{retractationcommande}prestashop>formulaire_e1b2374a2b9670a77ca0c7ae9199ad3a'] = 'To zamówienie nie kwalifikuje się (już) do odstąpienia online: upłynął termin ustawowy, wniosek został już złożony lub zamówienie nie jest objęte. W razie pytań skontaktuj się z naszym działem obsługi klienta.';
$_MODULE['<{retractationcommande}prestashop>formulaire_8fdb7ef7cb418c21ac083c86b78ce700'] = 'Prawo do odstąpienia nie ma zastosowania do niektórych umów (art. L221-28 Kodeksu konsumenckiego: towary wykonane na zamówienie lub spersonalizowane, towary szybko psujące się, towary odpieczętowane ze względów higienicznych itp.). Po złożeniu wniosek jest weryfikowany przez nasz dział obsługi klienta, który przekazuje Ci procedurę zwrotu. Zwrot następuje najpóźniej w ciągu 14 dni od odzyskania towaru lub otrzymania dowodu wysyłki tym samym sposobem płatności. Koszty odesłania ponosi konsument.';
$_MODULE['<{retractationcommande}prestashop>formulaire_40333b8af27e3198afa43c960e43a3b8'] = 'Prawo do odstąpienia';
$_MODULE['<{retractationcommande}prestashop>formulaire_aea7663609d13575de446154e8436973'] = 'Żadne zamówienie nie odpowiada tym danym. Sprawdź adres e-mail i numer referencyjny (widoczne w e-mailu z potwierdzeniem zamówienia).';
