$_MODULE['<{retractationcommande}prestashop>pdf-accuse_0acbcac4025fa540444c48cd5594df23'] = 'Koszty dostawy (zwrócone — całkowite odstąpienie)';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_b01439257d2c4065fdfa7b0ece09c658'] = 'Kwota do zwrotu (szacunkowo)';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_d7946d02e12c5949ea9345ba89b095c4'] = 'Częściowe odstąpienie: koszty dostawy są zwracane proporcjonalnie do odesłanych towarów (art. L221-24 francuskiego Kodeksu konsumenckiego). Ostateczna kwota zostanie potwierdzona przez nasz dział obsługi klienta.';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_a326ee07399805b54dda859c82d08e17'] = 'Wiadomość konsumenta';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_b6aaa57d1a0559fa210245cf8167735e'] = 'Dalszy przebieg procedury';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_fb258aad76f4abfa89becfda83844199'] = 'Twój wniosek zostanie zweryfikowany przez nasz dział obsługi klienta (dochowanie terminu ustawowego, wyłączenia przewidziane w artykule L221-28 francuskiego Kodeksu konsumenckiego). W przypadku zgodności procedura zwrotu zostanie Ci przekazana e-mailem. Prosimy nie odsyłać produktu(-ów) przed jej otrzymaniem. Zwrot nastąpi najpóźniej w ciągu 14 dni od odzyskania towaru lub otrzymania dowodu wysyłki tym samym sposobem płatności, który został użyty przy zamówieniu (art. L221-24). Bezpośrednie koszty odesłania ponosi konsument (art. L221-23).';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_cfdcc6b063cf374f1884714702a0756f'] = 'Ponieważ Twoje zamówienie nie zostało jeszcze wysłane w chwili złożenia wniosku, zwrot produktu nie będzie konieczny. Po weryfikacji przez nasz dział obsługi klienta (wyłączenia przewidziane w artykule L221-28 francuskiego Kodeksu konsumenckiego) wysyłka zostanie anulowana, a całość wpłaconych kwot zostanie zwrócona najpóźniej w ciągu 14 dni od Twojego wniosku tym samym sposobem płatności, który został użyty przy zamówieniu (art. L221-24).';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_5c2d9de00ffacf2c364b00b78de3b779'] = 'Niniejszy dokument stanowi potwierdzenie odbioru Twojego odstąpienia. Zachowaj go — numer referencyjny do podania w każdej korespondencji:';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_cd869423e6e1712e244df7d46926ae55'] = 'Przypomnienie o Twoich prawach — prawo do odstąpienia';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_28f6dc3c50525ce42dc3c3c6230b2e04'] = 'Termin';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_24e62b7e04a04435c6493925063099d7'] = 'Przysługuje Ci termin 14 dni na odstąpienie od umowy, bez konieczności uzasadniania decyzji (art. L221-18 francuskiego Kodeksu konsumenckiego). Liczenie rozpoczyna się w dniu następującym po dostawie towaru (lub po zawarciu umowy w przypadku świadczenia usług). Jeżeli termin upływa w sobotę, niedzielę lub dzień świąteczny, zostaje przedłużony do najbliższego dnia roboczego.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_ca4bdfe353ca54b512aa784846d90e0f'] = 'Zwrot środków';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_6541cabbb055c914336220caeaf4b99e'] = 'Zwrot obejmuje całość wpłaconych kwot, w tym standardowe koszty dostawy (proporcjonalnie w przypadku częściowego odstąpienia). Następuje najpóźniej w ciągu 14 dni od odzyskania towaru lub otrzymania dowodu jego wysyłki tym samym sposobem płatności, który został użyty przy zamówieniu (art. L221-24). Bezpośrednie koszty odesłania towaru ponosi konsument (art. L221-23).';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_364ec46bb0eefd5863d785498e0c8539'] = 'Wyjątki (art. L221-28)';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_cb0665e6df823aae3b2992c440175070'] = 'Z prawa do odstąpienia nie można skorzystać w szczególności w przypadku:';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_7e1ea9778afc631312c1791d817f91c0'] = 'towarów wykonanych według Twojej specyfikacji lub wyraźnie spersonalizowanych;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_0b6b365148cc6a798a4d9bec4e636d96'] = 'towarów, które mogą szybko ulec zepsuciu lub przeterminowaniu;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_9efb6136f62e038628c899b282f64011'] = 'towarów odpieczętowanych po dostawie, których nie można zwrócić ze względu na higienę lub ochronę zdrowia;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_8b8f626ccf32831a3fee474f675ea152'] = 'nagrań audio/wideo lub oprogramowania odpieczętowanych po dostawie;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_01449e6b663bbee9d407376945b3c9b6'] = 'treści cyfrowych dostarczanych bez nośnika materialnego, których wykonanie rozpoczęło się za Twoją zgodą;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_1d3b84dba66d1eb114fd8af178aa04d6'] = 'towarów, które po dostawie zostały nierozłącznie połączone z innymi artykułami.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_0095888b608335ea5982af9ada860f76'] = 'Dalsze losy Twojego wniosku';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_109c56e11ccf08ecc9e243bd1c4cb25f'] = 'Nasz dział obsługi klienta weryfikuje Twój wniosek, a następnie przesyła Ci procedurę zwrotu e-mailem. Prosimy nie odsyłać produktu(-ów) przed jej otrzymaniem oraz zwrócić towary kompletne, w stanie oryginalnym.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_de7d1a2208e88e0679183aa747db6042'] = 'Zamówienie niewysłane: zwrot produktu nie będzie konieczny. Nasz dział obsługi klienta weryfikuje Twój wniosek, anuluje wysyłkę i dokonuje zwrotu środków.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_2f45a1c26bcfdf568c08ed1a390d3cbd'] = 'W razie sporu';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_804c0cd637a7c9607f4e30b77e11a8ba'] = 'Jeżeli uważasz, że Twój wniosek nie został rozpatrzony zgodnie z przepisami, możesz skontaktować się z naszym działem obsługi klienta, a następnie bezpłatnie skorzystać z mediatora konsumenckiego (art. L612-1 francuskiego Kodeksu konsumenckiego).';
$_MODULE['<{retractationcommande}prestashop>order-detail_40333b8af27e3198afa43c960e43a3b8'] = 'Prawo do odstąpienia';
$_MODULE['<{retractationcommande}prestashop>order-detail_c611966bbf00695038db11996b48d73a'] = 'Wniosek';
$_MODULE['<{retractationcommande}prestashop>order-detail_13a014cb9de9f7cad88d5dafb70ecb41'] = 'z dnia';
$_MODULE['<{retractationcommande}prestashop>order-detail_6b9a33cdf67eb8f5e2ae805805a7f706'] = 'Przysługuje Ci ustawowy termin 14 dni na odstąpienie';
$_MODULE['<{retractationcommande}prestashop>order-detail_2cec369315350f7bdd5ed0f7c762be97'] = 'Odstąp';
$_MODULE['<{retractationcommande}prestashop>demande_a54afcca3ecc3d5b4891b1a75c73192d'] = 'Nie znaleziono zamówienia lub brak autoryzacji dostępu.';
$_MODULE['<{retractationcommande}prestashop>demande_ae6c41ce3d6f31f73f9d143bcae0f6b2'] = 'To zamówienie nie kwalifikuje się już do odstąpienia (upłynął termin ustawowy lub produkty są już w trakcie odstąpienia).';
$_MODULE['<{retractationcommande}prestashop>demande_3a6a3681876ab1e4c55fdecb70fab698'] = 'Wiadomość zawiera niedozwolone znaki.';
$_MODULE['<{retractationcommande}prestashop>demande_0f9a15225078e2688ee78b984640f46d'] = 'Żądana ilość przekracza ilość możliwą do odstąpienia.';
