$_MODULE['<{retractationcommande}prestashop>demande_9914a2c75cdd71876e656e7621e47300'] = 'Twoje odstąpienie zostało zarejestrowane pod numerem %s. Potwierdzenie odbioru zostało wysłane na Twój adres e-mail. Nasz dział obsługi klienta zweryfikuje Twój wniosek i prześle Ci procedurę zwrotu.';
$_MODULE['<{retractationcommande}prestashop>demande_f49c93cbb2dab9d8c4b41d7e8a0f346d'] = 'Twoje odstąpienie zostało zarejestrowane pod numerem %s. Potwierdzenie odbioru zostało wysłane na Twój adres e-mail. Ponieważ Twoje zamówienie nie zostało jeszcze wysłane, zwrot produktu nie będzie konieczny: po weryfikacji wysyłka zostanie anulowana, a Ty otrzymasz zwrot środków.';
$_MODULE['<{retractationcommande}prestashop>demande_5a06e6b127a7d1baaf18d35bde389969'] = 'Nasz dział obsługi klienta zweryfikuje warunki Twojego wniosku (ustawowy termin 14 dni, wyłączenia z artykułu L221-28). W przypadku zgodności procedura zwrotu zostanie Ci przekazana e-mailem, a następnie zwrot nastąpi najpóźniej w ciągu 14 dni od odzyskania towaru lub otrzymania dowodu wysyłki. Prosimy nie odsyłać produktu przed otrzymaniem procedury zwrotu.';
$_MODULE['<{retractationcommande}prestashop>demande_ba6e3c755dec44b85c76f4e9e919450b'] = 'Ponieważ Twoje zamówienie nie zostało jeszcze wysłane, zwrot produktu nie będzie konieczny. Po weryfikacji Twojego wniosku przez nasz dział obsługi klienta wysyłka zostanie anulowana, a całość wpłaconych kwot zostanie zwrócona najpóźniej w ciągu 14 dni od Twojego wniosku tym samym sposobem płatności (art. L221-24).';
$_MODULE['<{retractationcommande}prestashop>demande_b91f8258aeb37ba358b04427913bd6b1'] = 'Do sprawdzenia: termin 14 dni, wyłączenia ustawowe (art. L221-28), produkty już zwrócone.';
$_MODULE['<{retractationcommande}prestashop>demande_ecbc815f858a7d4a0ff0fe67f6eea2a3'] = 'ZAMÓWIENIE NIEWYSŁANE — anulowanie przed wysyłką: nie oczekuje się zwrotu produktu. Do sprawdzenia: wyłączenia ustawowe (art. L221-28). Pamiętaj o zablokowaniu wysyłki przed zatwierdzeniem.';
$_MODULE['<{retractationcommande}prestashop>demande_5f0d073c461f238ea2622dc70766a38f'] = 'Niewysłane w chwili złożenia wniosku';
